import{_ as e,H as a,f as l,i as r}from"./chunks/framework.eFU6Tutu.js";const u=JSON.parse('{"title":"Салат (латук)","description":"","frontmatter":{},"headers":[],"relativePath":"plants/salad.md","filePath":"plants/salad.md"}'),i={name:"plants/salad.md"};function n(s,t,d,o,h,f){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="салат-латук" tabindex="-1">Салат (латук) <a class="header-anchor" href="#салат-латук" aria-label="Permalink to &quot;Салат (латук)&quot;">​</a></h1><p>Салат — одна из самых благодарных культур для домашнего выращивания. Он быстро растёт, неприхотлив и даёт свежую, хрустящую зелень, богатую витаминами, прямо с подоконника. Листья используют в салатах, бутербродах и как украшение блюд.</p><h2 id="описание" tabindex="-1">Описание <a class="header-anchor" href="#описание" aria-label="Permalink to &quot;Описание&quot;">​</a></h2><p>Салат — однолетнее холодостойкое растение семейства Астровые. В пищу употребляют листья, которые бывают зелёными, жёлтыми или с красноватым оттенком, гладкими или пузырчатыми, с волнистым или резным краем. В домашних условиях чаще всего выращивают листовые сорта, которые образуют розетку из листьев, но можно попробовать и кочанные.</p><h2 id="популярные-сорта-для-дома" tabindex="-1">Популярные сорта для дома <a class="header-anchor" href="#популярные-сорта-для-дома" aria-label="Permalink to &quot;Популярные сорта для дома&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Сорт</th><th style="text-align:left;">Тип</th><th style="text-align:left;">Особенности</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Кресс-салат</strong> (например, <code>Витаминчик</code>, <code>Дукат</code>)</td><td style="text-align:left;">Листовой</td><td style="text-align:left;">Сверхскороспелый (2-3 недели), пряный горчичный вкус. Можно выращивать без земли (на вате/губке).</td></tr><tr><td style="text-align:left;"><strong>Московский парниковый</strong></td><td style="text-align:left;">Листовой</td><td style="text-align:left;">Раннеспелый, нежный, сочный, светло-зеленый. Один из самых популярных для окон.</td></tr><tr><td style="text-align:left;"><strong>Изумрудное кружево</strong></td><td style="text-align:left;">Листовой</td><td style="text-align:left;">Среднеранний, хрустящий, ярко-зеленый, быстро отрастает после срезки.</td></tr><tr><td style="text-align:left;"><strong>Балет</strong></td><td style="text-align:left;">Листовой</td><td style="text-align:left;">Позднеспелый, маслянистый, светло-зеленый, устойчив к недостатку света.</td></tr><tr><td style="text-align:left;"><strong>Лолло Росса</strong></td><td style="text-align:left;">Листовой</td><td style="text-align:left;">Среднеранний, очень декоративный, с гофрированными листьями красно-бордового цвета.</td></tr><tr><td style="text-align:left;"><strong>Китеж</strong></td><td style="text-align:left;">Кочанный</td><td style="text-align:left;">Среднеранний, образует небольшие рыхлые кочаны красно-коричневого цвета.</td></tr></tbody></table><h2 id="уход" tabindex="-1">Уход <a class="header-anchor" href="#уход" aria-label="Permalink to &quot;Уход&quot;">​</a></h2><p>Подробнее об уходе за салатом и другой зеленью читайте в <a href="/care/greens/#салат">гайде по уходу за зеленью</a>.</p><h2 id="как-использовать-в-еде" tabindex="-1">Как использовать в еде <a class="header-anchor" href="#как-использовать-в-еде" aria-label="Permalink to &quot;Как использовать в еде&quot;">​</a></h2><ul><li>Классические салаты со свежими овощами</li><li>Бутерброды и сэндвичи</li><li>Гарнир к мясным блюдам</li><li>Смузи и зеленые коктейли</li><li>Как основа для «тарелки» с начинкой</li></ul><h2 id="полезные-своиства" tabindex="-1">Полезные свойства <a class="header-anchor" href="#полезные-своиства" aria-label="Permalink to &quot;Полезные свойства&quot;">​</a></h2><ul><li>Низкокалорийный (около 15 ккал на 100 г), идеален для диетического питания.</li><li>Содержит витамины А, С, К, группы В и фолиевую кислоту.</li><li>Богат калием, железом и магнием.</li><li>Благодаря содержанию лактуцина успокаивает нервную систему и улучшает сон.</li><li>Улучшает пищеварение и работу кишечника.</li></ul><h2 id="источники-информации" tabindex="-1">Источники информации <a class="header-anchor" href="#источники-информации" aria-label="Permalink to &quot;Источники информации&quot;">​</a></h2><ul><li><a href="https://www.ogorod.ru/ru/main/useful/14704/Vyrastit-salat-zimoy-na-podokonnike.htm" target="_blank" rel="noreferrer">Огород.ru — Вырастить салат зимой на подоконнике? Легко!</a></li><li><a href="https://ru.wikihow.com/%D0%B2%D1%8B%D1%80%D0%B0%D1%89%D0%B8%D0%B2%D0%B0%D1%82%D1%8C-%D1%81%D0%B0%D0%BB%D0%B0%D1%82-%D0%B2-%D0%B4%D0%BE%D0%BC%D0%B0%D1%88%D0%BD%D0%B8%D1%85-%D1%83%D1%81%D0%BB%D0%BE%D0%B2%D0%B8%D1%8F%D1%85" target="_blank" rel="noreferrer">wikiHow — Как выращивать салат в домашних условиях</a></li><li><a href="https://azbyka.ru/garden/nyuansy-pri-vyrashhivanii-ovoshhej-i-zeleni-na-podokonnike/" target="_blank" rel="noreferrer">Азбука садовода — Нюансы при выращивании овощей и зелени</a></li></ul><h2 id="похожие-растения" tabindex="-1">Похожие растения <a class="header-anchor" href="#похожие-растения" aria-label="Permalink to &quot;Похожие растения&quot;">​</a></h2><ul><li><a href="/plants/dill.html">Укроп</a></li><li><a href="/plants/parsley.html">Петрушка</a></li><li><a href="/plants/chives.html">Лук (зелёный)</a></li><li><a href="/plants/basil.html">Базилик</a></li><li><a href="/plants/microgreens.html">Микрозелень</a></li></ul>',16)])])}const c=e(i,[["render",n]]);export{u as __pageData,c as default};
